/**
 * @fileoverview ViewTimeline component definition for JIT pipeline.
 *
 * Bundles design tokens, state machine config, template slot definitions,
 * and Custom Element metadata.
 *
 * @module module/ViewTimeline.def
 */

import razyui from '../index.js';
import { PART } from './ViewTimeline/constants.js';

/**
 * The definition object for the ViewTimeline component.
 * Contains metadata, tokens, states, templates, variants, and attribute mappings.
 *
 * @type {Object}
 */
export const ViewTimelineDef = {
    name: 'ViewTimeline',
    tag: 'rui-view-timeline',

    // ═══════════════════════════════════════
    //  Design Tokens
    // ═══════════════════════════════════════
    tokens: {
        prefix: 'vt',
        tokens: {
            // ViewTimeline is primarily JS-driven and uses the --vt
            // custom property for scroll progress. No visual tokens needed.
        },
    },

    // ═══════════════════════════════════════
    //  State Machine
    // ═══════════════════════════════════════
    states: {
        initial: 'idle',
        states: {
            idle: {
                on: { ENTER: 'visible' },
            },
            visible: {
                on: { FULL: 'full', EXIT: 'idle' },
            },
            full: {
                on: { EXIT: 'idle', PARTIAL: 'visible' },
            },
        },
        effects: {
            visible(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('vt-visible');
                if (ctx.el) razyui(ctx.el).removeClass('vt-full');
            },
            full(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('vt-visible', 'vt-full');
            },
            idle(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('vt-visible', 'vt-full');
            },
        },
    },

    // ═══════════════════════════════════════
    //  Template Slots
    // ═══════════════════════════════════════
    template: {
        slots: {
            element: { element: 'div', classes: ['vt-element'] },
        },
    },

    // ═══════════════════════════════════════
    //  Custom Element
    // ═══════════════════════════════════════
    observedAttrs: ['threshold', 'once', 'animation'],
    attrMap: {
        threshold: 'threshold',
        once:      'once',
        animation: 'animation',
    },

    jitParts: {
        [PART.ELEMENT]: PART.ELEMENT,
    },
};

export default ViewTimelineDef;
