/**
 * @fileoverview ViewTimeline barrel — re-exports from modular implementation.
 * Kept at module root for backward compatibility with razyui.load().
 *
 * @module module/ViewTimeline
 */
import { default as razyui } from '../index.js';
import { ViewTimelineDef as DEF } from './ViewTimeline.def.js';
import ViewTimeline from './ViewTimeline/index.js';

// ── Module registration ──
razyui.ViewTimeline = ViewTimeline;

// ── JIT Component Definition registration ──
if (razyui.JIT?.defineComponent) {
    razyui.JIT.defineComponent(DEF.name, DEF);
}

// ── Custom Element registration ──
/**
 * Registers the ViewTimeline component as a custom element.
 *
 * @function registerElement
 */
export function registerElement() {
    const { tag, observedAttrs, attrMap } = DEF.ce;
    if (customElements.get(tag)) return;
    customElements.define(tag, class extends HTMLElement {
        static get observedAttributes() { return observedAttrs; }
        connectedCallback()    { this._ctrl = new ViewTimeline(this, this.dataset); }
        disconnectedCallback() { this._ctrl?.destroy?.(); }
        attributeChangedCallback(n, o, v) {
            if (o !== v && this._ctrl) this._ctrl[attrMap[n]] = v;
        }
        get control() { return this._ctrl; }
    });
}

export default ViewTimeline;
export const stylesheet = null;
