/**
 * @fileoverview ViewTimeline component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, presets, defaults, magic numbers
 *   helpers.js   — pure utility functions (buildAnimConfig, calcProgress)
 *   events.js    — global scroll / resize listener setup
 *   view.js      — DOM updates + cleanup
 *
 * @module module/ViewTimeline
 */

import { default as razyui } from '../../index.js';
import { ViewTimelineDef as DEF } from '../ViewTimeline.def.js';

import { DEFAULTS, CSS_VAR_PROGRESS, PROGRESS_EPSILON, PROGRESS_DIGITS, REVEAL_DURATION, PART } from './constants.js';
import { buildAnimConfig, calcProgress } from './helpers.js';
import { initGlobalListeners } from './events.js';
import { applyProgress, cleanupElement } from './view.js';

/**
 * ViewTimeline — v2
 *
 * Scroll-driven animations that change element properties based on
 * viewport visibility percentage — like CSS animation-timeline: view().
 *
 * Features:
 *   - Track element visibility as it scrolls through the viewport
 *   - Map visibility progress (0→1) to CSS property changes
 *   - Keyframe-based multi-step animations
 *   - Built-in presets (fade-up, zoom-in, blur-in, etc.)
 *   - Easing functions
 *   - Range control: 'entry', 'exit', 'cover', 'contain'
 *   - Once mode: animate in, then freeze
 *   - Stagger support for batch elements
 *   - CSS custom property --vt on each element
 *   - rAF-throttled for 60 fps performance
 *   - getControl() API
 *
 * Config:
 *   preset    — 'fade-up','fade-down','fade-left','fade-right',
 *               'zoom-in','zoom-out','slide-up','slide-down','blur-in'
 *   from/to   — shorthand { opacity: 0, y: 40 } → { opacity: 1, y: 0 }
 *   keyframes — multi-step { 0: {...}, 50: {...}, 100: {...} }
 *   range     — 'entry' (default), 'exit', 'cover', 'contain'
 *   easing    — 'linear','ease','ease-in','ease-out','ease-in-out'
 *   once      — freeze at final state (default true)
 *   offset    — px shift to delay/advance trigger point
 *
 * Animatable properties:
 *   opacity, x, y, scale, scaleX, scaleY, rotate, skewX, skewY, blur
 *
 * Callbacks:
 *   onProgress(progress, element)
 * 
 * @class ViewTimeline
 */

// ── ViewTimeline class ───────────────────────

const ViewTimeline = class {

    // ── Static pool & scroll loop ────────────

    /** @type {Set<ViewTimeline>} */
    static #pool = new Set();

    /**
     * Initializes global listeners for the scroll loop.
     * @private
     */
    static #init() {
        initGlobalListeners(() => ViewTimeline.#tick());
    }

    /**
     * Ticks the scroll loop, updating all instances.
     * @private
     */
    static #tick() {
        for (const inst of ViewTimeline.#pool) {
            inst.update();
        }
    }

    /**
     * Batch-observe multiple elements with optional stagger.
     *
     * **Time-based stagger** (existing):
     *   ViewTimeline.observe('.card', { preset: 'fade-up', stagger: 50 });
     *   Elements at the same Y row get cascading delays (50ms apart).
     *
     * **Scroll-driven stagger** (new):
     *   ViewTimeline.observe('.card', { preset: 'fade-up', scrollStagger: 40 });
     *   Each element in a row starts its animation 40px of scroll after
     *   the previous one. Progress is scroll-driven, not time-based.
     *
     * @param {string|NodeList|Element[]} selector - The elements to observe.
     * @param {object} [config={}] - Configuration options.
     * @returns {ViewTimeline[]} An array of ViewTimeline instances.
     */
    static observe(selector, config = {}) {
        const els = razyui(selector);

        const stagger = config.stagger || 0;
        const scrollStagger = config.scrollStagger || 0;

        // Group elements by Y-position so stagger resets per row.
        const Y_TOLERANCE = 5; // px — accounts for sub-pixel rounding

        // ── Scroll-driven stagger (two-pass) ─────────────────
        // Needs total row size upfront to compress each element's
        // animation range so they all finish within the natural scroll area.
        if (scrollStagger > 0) {
            let lastY = -Infinity;
            const rows = [];  // array of element arrays
            let currentRow = [];

            for (const el of els) {
                const rect = el.getBoundingClientRect();
                if (Math.abs(rect.top - lastY) > Y_TOLERANCE) {
                    if (currentRow.length) rows.push(currentRow);
                    currentRow = [];
                    lastY = rect.top;
                }
                currentRow.push(el);
            }
            if (currentRow.length) rows.push(currentRow);

            // Cap totalStagger so travel distance never collapses to zero.
            // Maximum safe compress = 60% of viewport height.
            const maxCompress = window.innerHeight * 0.6;

            const instances = [];
            for (const row of rows) {
                const rawTotal = (row.length - 1) * scrollStagger;
                const totalStagger = Math.min(rawTotal, maxCompress);
                // Re-derive per-element offset from the clamped total
                const step = row.length > 1 ? totalStagger / (row.length - 1) : 0;
                row.forEach((el, idx) => {
                    const elConfig = { ...config };
                    elConfig._scrollOffset = idx * step;
                    elConfig._scrollTotalStagger = totalStagger;
                    instances.push(new ViewTimeline(el, elConfig));
                });
            }
            return instances;
        }

        // ── Time-based stagger or no stagger ─────────────────
        let lastY = -Infinity;
        let rowIdx = 0;

        return els.map((el) => {
            const elConfig = { ...config };
            if (stagger > 0) {
                const rect = el.getBoundingClientRect();
                if (Math.abs(rect.top - lastY) > Y_TOLERANCE) {
                    rowIdx = 0;
                    lastY = rect.top;
                }
                elConfig._staggerDelay = rowIdx * stagger;
                rowIdx++;
            }
            return new ViewTimeline(el, elConfig);
        });
    }

    /**
     * Destroys all active instances and unbinds global listeners.
     */
    static destroyAll() {
        for (const inst of ViewTimeline.#pool) {
            inst.destroy();
        }
    }

    // ── Instance fields ──────────────────────

    /** @type {HTMLElement} */
    #el = null;
    /** @type {Object} */
    #config = {};
    /** @type {Object} */
    #anim = null;      // razyui.animate() controller
    /** @type {number} */
    #progress = -1;
    /** @type {boolean} */
    #done = false;
    /** @type {boolean} */
    #destroyed = false;

    // ── Trigger / stagger fields ─────────────
    /** @type {number} */
    #revealDelay = 0;           // ms delay before reveal (0 = immediate)
    /** @type {boolean} */
    #revealTriggered = false;   // whether entry has been detected
    /** @type {boolean} */
    #revealAnimating = false;   // whether time-based animation is running
    /** @type {number} */
    #revealTimer = 0;           // setTimeout ID for stagger cleanup

    // ── Constructor ──────────────────────────

    /**
     * Creates an instance of ViewTimeline.
     * @param {string|HTMLElement} selectorOrEl - The element or selector to observe.
     * @param {Object} [config={}] - Configuration options.
     */
    constructor(selectorOrEl, config = {}) {
        const el = razyui(selectorOrEl)[0];
        if (!el) { console.warn('ViewTimeline: element not found \u2192', selectorOrEl); return; }

        this.#el = el;
        this.#config = { ...DEFAULTS, ...config };

        // Build animation config from preset / from-to / keyframes
        const animCfg = buildAnimConfig(this.#config);
        if (!animCfg) return;

        this.#anim = razyui.animate(el, animCfg);
        PART.ELEMENT.apply(razyui(el));

        // ── Stagger delay (set by observe()) ──
        this.#revealDelay = this.#config._staggerDelay || 0;

        // Register in pool & init global listeners
        ViewTimeline.#pool.add(this);
        ViewTimeline.#init();

        // Apply initial state immediately
        this.update();
    }

    // ── Per-frame update (called by static tick) ──

    /**
     * Updates the animation progress based on scroll position.
     */
    update() {
        if (this.#done || this.#destroyed || this.#revealAnimating) return;

        const progress = calcProgress(this.#el, this.#config, razyui.clamp);

        // ── Stagger reveal: time-based animation with cascading delay ──
        // Only used when observe() sets _staggerDelay (stagger > 0).
        if ('_staggerDelay' in this.#config) {
            if (!this.#revealTriggered) {
                // Hold at from-state (progress 0) until triggered
                if (this.#progress !== 0) {
                    this.#progress = 0;
                    applyProgress(this.#el, 0, this.#anim);
                }
                // Trigger when element enters viewport
                if (progress > 0) {
                    this.#revealTriggered = true;
                    if (this.#revealDelay > 0) {
                        this.#revealTimer = setTimeout(() => {
                            this.#revealTimer = 0;
                            this.#playReveal();
                        }, this.#revealDelay);
                    } else {
                        // First element in stagger group (delay 0): play immediately
                        this.#playReveal();
                    }
                }
            }
            // Stagger mode is fully managed by #playReveal — never
            // fall through to scroll-driven progress below.
            return;
        }

        // ── Scroll-driven progress ────────────────────────────
        // Skip if unchanged (within epsilon)
        if (Math.abs(progress - this.#progress) < PROGRESS_EPSILON) return;

        this.#progress = progress;

        // Delegate DOM mutations to view module
        applyProgress(this.#el, progress, this.#anim);

        // Once mode: freeze when fully revealed
        if (this.#config.once && progress >= 1) {
            this.#done = true;
            this.#anim.settle();
        }

        // Callback
        if (typeof this.#config.onProgress === 'function') {
            this.#config.onProgress(progress, this.#el);
        }
    }

    /**
     * Play the full reveal animation (0 → 1) over REVEAL_DURATION ms.
     * Called once when `once: true` and the element enters the viewport
     * (optionally after a stagger delay).
     * @private
     */
    #playReveal() {
        if (this.#destroyed) return;

        this.#revealAnimating = true;
        this.#anim.promote();      // re-enable will-change for the animation
        this.#anim.at(0);          // ensure we start from the from-state

        this.#anim.to(1, REVEAL_DURATION, this.#config.easing).then(() => {
            this.#revealAnimating = false;
            this.#progress = 1;
            applyProgress(this.#el, 1, this.#anim);

            // Freeze at final state
            this.#done = true;
            this.#anim.settle();

            // Callback at completion
            if (typeof this.#config.onProgress === 'function') {
                this.#config.onProgress(1, this.#el);
            }
        });
    }

    // ── Public API ───────────────────────────

    /**
     * Gets the controller object for the ViewTimeline instance.
     * @returns {Object} The controller object.
     */
    getControl() {
        const self = this;
        return {
            /** Get current progress (0-1) */
            get progress() { return self.#progress; },

            /** Get the target element */
            get element() { return self.#el; },

            /** Whether the animation has completed (once mode) */
            get done() { return self.#done; },

            /** Force a progress value (bypasses scroll calculation) */
            setProgress: (p) => {
                self.#progress = razyui.clamp(p, 0, 1);
                razyui(self.#el).css(CSS_VAR_PROGRESS, self.#progress.toFixed(PROGRESS_DIGITS));
                self.#anim.at(self.#progress);
            },

            /** Reset to start state */
            reset: () => {
                self.#done = false;
                self.#progress = -1;
                self.#revealTriggered = false;
                self.#revealAnimating = false;
                if (self.#revealTimer) { clearTimeout(self.#revealTimer); self.#revealTimer = 0; }
                self.#anim.promote();
                self.update();
            },

            /** Destroy this instance */
            destroy: () => self.destroy(),
            get destroyed() { return self.#destroyed; },
        };
    }

    /**
     * Destroys the ViewTimeline instance, cleaning up DOM and events.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        if (this.#revealTimer) { clearTimeout(this.#revealTimer); this.#revealTimer = 0; }
        ViewTimeline.#pool.delete(this);
        cleanupElement(this.#el, this.#anim);
    }
};

export default ViewTimeline;
